// Get the content (HTML) from the previous node (HTTP Request Node)
const content = $json["data"];  // This contains the raw HTML data

// Log the content for debugging purposes
console.log('Content:', content);

// Regular expression to search for both RSS and Atom feed links in the HTML content
const rssFeedRegex = /<link[^>]+rel=["']alternate["'][^>]+type=["'](application\/rss\+xml|application\/atom\+xml)["'][^>]+href=["']([^"']+)["']/i;

// Extract the website URL dynamically from the input node (previous node's data)
const websiteUrl = $('Fetch Each URL').item.json.websiteUrl;

// Function to check if the content is valid HTML and contains RSS feeds
if (content.trim().startsWith('<!DOCTYPE html>') || content.trim().startsWith('<html')) {
    console.log("Content is HTML");

    // Use the regular expression to find the RSS feed link in the HTML content
    const match = content.match(rssFeedRegex);

    // If the RSS feed link is found
    if (match) {
        console.log("RSS Feed URL found:", match[2]);  // Log the RSS feed URL (match[2] contains the URL)

        // Check if the URL is relative and prepend the base URL (websiteUrl)
        let fullRssFeedUrl = match[2];

        // If the RSS feed URL is relative (does not start with 'http')
        if (!fullRssFeedUrl.startsWith('http')) {
            fullRssFeedUrl = websiteUrl + fullRssFeedUrl;  // Concatenate the website URL with the relative URL
        }

        return {
            rssFeedFound: true,
            rssFeedUrl: fullRssFeedUrl // The full RSS feed URL
        };
    } else {
        console.log("No RSS Feed URL found in HTML");  // Log no match found
        return {
            rssFeedFound: false
        };
    }
} else {
    // If the content is not HTML, return false
    console.log("Content is not HTML");
    return {
        rssFeedFound: false
    };
}

