// Get the list of new titles from Fetched Article
const newTitles = $('Fetched Article').all().map(item => item.json.title);

// Get the list of existing titles from Google Sheets (or wherever you're storing them)
const titlesList = $json["titlesList"];

// Flag to indicate if all titles are found
let allTitlesFound = true;

// Array to store titles that were not found
let notFoundTitles = [];

// Iterate over each new title and check if it exists in titlesList
for (let newTitle of newTitles) {
    if (!titlesList.includes(newTitle)) {
        // If the title is not found, mark it and add to the notFoundTitles array
        allTitlesFound = false;
        notFoundTitles.push(newTitle);
    }
}

// Return the result (true/false) and the list of not found titles
return [
  {
    json: {
      allTitlesFound: allTitlesFound,  // This will be true if all titles are found
      notFoundTitles: notFoundTitles  // This will contain the titles that are not found
    }
  }
];

